package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetAllowMissingColumnNames_Default() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        boolean allowMissingColumnNames = getAllowMissingColumnNamesViaReflection(format);
        assertFalse(allowMissingColumnNames);
    }

    @Test
    void testGetAllowMissingColumnNames_WithAllowMissingColumnNames() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames();
        boolean allowMissingColumnNames = getAllowMissingColumnNamesViaReflection(format);
        assertTrue(allowMissingColumnNames);
    }

    @Test
    void testGetAllowMissingColumnNames_WithAllowMissingColumnNamesFalse() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(false);
        boolean allowMissingColumnNames = getAllowMissingColumnNamesViaReflection(format);
        assertFalse(allowMissingColumnNames);
    }

    @Test
    void testGetAllowMissingColumnNames_WithAllowMissingColumnNamesTrue() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(true);
        boolean allowMissingColumnNames = getAllowMissingColumnNamesViaReflection(format);
        assertTrue(allowMissingColumnNames);
    }

    @Test
    void testGetAllowMissingColumnNames_ExcelFormat() throws Exception {
        CSVFormat excelFormat = CSVFormat.EXCEL;
        boolean allowMissingColumnNames = getAllowMissingColumnNamesViaReflection(excelFormat);
        assertTrue(allowMissingColumnNames);
    }

    private boolean getAllowMissingColumnNamesViaReflection(CSVFormat format) throws Exception {
        Field field = CSVFormat.class.getDeclaredField("allowMissingColumnNames");
        field.setAccessible(true);
        return field.getBoolean(format);
    }
}
